import{_ as e,a as n,b as t,c as l}from"./chunks/下载好后的视频.pSSnkGgz.js";import{_ as i,o as d,c as r,a2 as s}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Magnet Transfer","description":"","frontmatter":{},"headers":[],"relativePath":"ms-MY/Other/magnet-transfer.md","filePath":"ms-MY/Other/magnet-transfer.md","lastUpdated":1781962217000}'),o={name:"ms-MY/Other/magnet-transfer.md"};function u(p,a,m,g,k,h){return d(),r("div",null,[...a[0]||(a[0]=[s('<h1 id="magnet-transfer" tabindex="-1">Magnet Transfer <a class="header-anchor" href="#magnet-transfer" aria-label="Permalink to &quot;Magnet Transfer&quot;">​</a></h1><p>Magnet transfer memuat turun files daripada magnet link dan meng-uploadnya secara automatik ke cloud storage channel yang anda pilih.</p><p>Ia berguna untuk memindahkan anime episodes, videos, archives dan files seumpamanya. Paste magnet link, ImgBed mencipta background download task. Selepas download selesai, file di-upload ke ImgBed dan final link muncul dalam upload list.</p><p><img src="'+e+'" alt="Magnet transfer" loading="lazy"></p><h2 id="di-mana-untuk-menggunakannya" tabindex="-1">Di Mana Untuk Menggunakannya <a class="header-anchor" href="#di-mana-untuk-menggunakannya" aria-label="Permalink to &quot;Di Mana Untuk Menggunakannya&quot;">​</a></h2><p>Magnet transfer entry berada dalam homepage upload area.</p><p>Paste magnet link ke input box, pilih <code>Transfer</code>, kemudian upload.</p><p><img src="'+n+'" alt="Upload anime" loading="lazy"></p><h2 id="sebelum-penggunaan-pertama" tabindex="-1">Sebelum Penggunaan Pertama <a class="header-anchor" href="#sebelum-penggunaan-pertama" aria-label="Permalink to &quot;Sebelum Penggunaan Pertama&quot;">​</a></h2><p>Configure magnet transfer dalam admin panel dahulu.</p><p>Biasanya anda perlukan:</p><ol><li>GitHub account untuk menjalankan download task.</li><li>Cloud upload channel, seperti Google Drive atau OneDrive.</li><li>Target upload directory.</li><li>Task timeout.</li></ol><p>Selepas settings sedia, kembali ke homepage dan paste magnet link untuk memulakan transfer.</p><h2 id="upload-magnet-link" tabindex="-1">Upload Magnet Link <a class="header-anchor" href="#upload-magnet-link" aria-label="Permalink to &quot;Upload Magnet Link&quot;">​</a></h2><ol><li>Paste magnet link ke homepage upload box.</li><li>Pastikan mode ditetapkan kepada <code>Transfer</code>.</li><li>Klik upload.</li><li>Tunggu ImgBed mencipta magnet task.</li><li>Selepas task bermula, gunakan floating panel <code>Magnet Tasks</code> di penjuru kanan bawah untuk menyemak progress.</li></ol><p>Download dan upload boleh mengambil masa. Speed bergantung pada magnet resource, GitHub runtime environment dan selected cloud storage channel.</p><p><img src="'+t+'" alt="Magnet downloading" loading="lazy"></p><h2 id="selepas-completion" tabindex="-1">Selepas Completion <a class="header-anchor" href="#selepas-completion" aria-label="Permalink to &quot;Selepas Completion&quot;">​</a></h2><p>Selepas task complete, upload list menunjukkan file name dan link.</p><p>Videos menunjukkan video preview, images menunjukkan image preview, dan other files menunjukkan regular file icon.</p><p><img src="'+l+'" alt="Downloaded video" loading="lazy"></p><p>Anda boleh copy:</p><table tabindex="0"><thead><tr><th>Link Type</th><th>Use Case</th></tr></thead><tbody><tr><td>Original link</td><td>Direct file access</td></tr><tr><td>Markdown</td><td>Markdown posts atau notes</td></tr><tr><td>HTML</td><td>Web page code</td></tr><tr><td>BBCode</td><td>Forums yang menyokong BBCode</td></tr></tbody></table><h2 id="magnet-task-panel" tabindex="-1">Magnet Task Panel <a class="header-anchor" href="#magnet-task-panel" aria-label="Permalink to &quot;Magnet Task Panel&quot;">​</a></h2><p>Magnet task panel di penjuru kanan bawah menunjukkan task count, task name, progress dan final status.</p><p>Common states:</p><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td>Waiting</td><td>Task telah dicipta dan menunggu untuk run.</td></tr><tr><td>Downloading</td><td>Magnet resource sedang dimuat turun.</td></tr><tr><td>Uploading</td><td>File telah download dan sedang di-upload ke cloud storage.</td></tr><tr><td>Completed</td><td>Upload berjaya dan link boleh disalin.</td></tr><tr><td>Failed</td><td>Task tidak selesai dengan berjaya. Semak message dan cuba lagi.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Jika magnet link mengandungi multiple files, ImgBed mengutamakan main completed file untuk display.</li><li>Large files mengambil masa lebih lama. Tunggu task selesai sebelum refresh page.</li><li>Jika magnet resource tiada available peers, ia mungkin sangat perlahan atau gagal.</li><li>Jika cloud account kehabisan quota, authorization expired, atau upload directory salah, task boleh gagal.</li><li>Video preview mungkin mengambil beberapa saat selepas upload complete.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="tiada-apa-bermula-selepas-paste-magnet-link" tabindex="-1">Tiada Apa Bermula Selepas Paste Magnet Link <a class="header-anchor" href="#tiada-apa-bermula-selepas-paste-magnet-link" aria-label="Permalink to &quot;Tiada Apa Bermula Selepas Paste Magnet Link&quot;">​</a></h3><p>Pastikan magnet transfer enabled dalam admin panel dan GitHub account serta cloud channel yang boleh digunakan telah dipilih.</p><h3 id="download-sentiasa-perlahan" tabindex="-1">Download Sentiasa Perlahan <a class="header-anchor" href="#download-sentiasa-perlahan" aria-label="Permalink to &quot;Download Sentiasa Perlahan&quot;">​</a></h3><p>Magnet speed bergantung pada resource itu sendiri. Jika tiada available peers, download mungkin sangat perlahan atau mustahil.</p><h3 id="tiada-preview-selepas-upload" tabindex="-1">Tiada Preview Selepas Upload <a class="header-anchor" href="#tiada-preview-selepas-upload" aria-label="Permalink to &quot;Tiada Preview Selepas Upload&quot;">​</a></h3><p>Mula-mula pastikan file link boleh dibuka. Video files mungkin memerlukan sedikit masa untuk load dalam browser, atau anda boleh buka link secara langsung.</p><h3 id="apa-perlu-disemak-jika-task-gagal" tabindex="-1">Apa Perlu Disemak Jika Task Gagal? <a class="header-anchor" href="#apa-perlu-disemak-jika-task-gagal" aria-label="Permalink to &quot;Apa Perlu Disemak Jika Task Gagal?&quot;">​</a></h3><p>Semak sama ada magnet link valid, cloud channel berfungsi dan upload directory betul. Kemudian submit task semula.</p>',38)])])}const P=i(o,[["render",u]]);export{f as __pageData,P as default};
